css:
@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;500;600;700&display=swap');

/* ── Base ── */
* {
    font-family: 'Cairo', sans-serif;
    box-sizing: border-box;
}

body {
    font-weight: 500;
    color: #2f3b52;
    background: #ffffff;
    line-height: 1.7;
    font-size: 13px;
}

p, div, li, span {
    font-weight: 500;
    color: #2f3b52;
}

/* ── Headings ── */
h1 {
    font-weight: 700;
    color: #1a2640;
    font-size: 20px;
    border-bottom: 2px solid #e0e6ed;
    padding-bottom: 6px;
    margin-bottom: 14px;
}

h2 {
    font-weight: 700;
    color: #1a2640;
    font-size: 16px;
    margin-bottom: 10px;
}

h3 {
    font-weight: 600;
    color: #2f3b52;
    font-size: 14px;
}

h4, h5, h6 {
    font-weight: 600;
    color: #4a5a70;
}

/* ── Labels ── */
label {
    font-weight: 600;
    color: #2f3b52;
    background-color: #f0f4f8;
    padding: 2px 8px;
    border-radius: 4px;
    display: inline-block;
    border: 1px solid #dce3ea;
    font-size: 11px;
}

/* ── Tables ──
   text-align: start = right in RTL, left in LTR — never forced
── */
table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 12px;
}

th {
    background-color: #f0f4f8;
    color: #1a2640;
    font-weight: 700;
    padding: 8px 12px;
    border: 1px solid #dce3ea;
    text-align: start;
    font-size: 12px;
}

td {
    padding: 7px 12px;
    border: 1px solid #e6eaef;
    color: #2f3b52;
    font-weight: 500;
    text-align: start;
    font-size: 12px;
}

tr:nth-child(even) td {
    background-color: #f8fafc;
}

tfoot td,
tfoot th {
    font-weight: 700;
    background-color: #f0f4f8;
    color: #1a2640;
    border-top: 2px solid #dce3ea;
}

/* ── RTL / LTR helpers (manual override per section) ── */
.rtl {
    direction: rtl;
    text-align: right;
}

.ltr {
    direction: ltr;
    text-align: left;
}

/* ── Links ── */
a {
    color: #2f3b52;
    text-decoration: none;
}

/* ── Print media ── */
@media print {
    body { font-size: 11px; }
    h1   { font-size: 16px; }
    h2   { font-size: 14px; }
    h3   { font-size: 12px; }
    table { page-break-inside: auto; }
    tr    { page-break-inside: avoid; }
    thead { display: table-header-group; }
}
